function formatNpr(amount) {
    if (amount == null) return 'NPR 0';
    return `NPR ${Math.round(amount).toLocaleString('en-NP')}`;
}
function getTodayStr() {
    return new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    });
}
function formatTime(iso) {
    if (!iso) return '—';
    try {
        const d = new Date(iso);
        if (isNaN(d.getTime())) return iso;
        return d.toLocaleTimeString('en-US', {
            hour: '2-digit',
            minute: '2-digit',
            hour12: true
        });
    } catch  {
        return iso;
    }
}
function formatDateShort(iso) {
    try {
        const d = new Date(iso);
        if (isNaN(d.getTime())) return iso;
        return d.toLocaleDateString('en-US', {
            weekday: 'short',
            month: 'short',
            day: 'numeric'
        });
    } catch  {
        return iso;
    }
}
function formatTimeSeconds(date) {
    if (!date) return '';
    return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
    });
}
function pctColor(pct) {
    if (pct >= 80) return '#16A34A';
    if (pct >= 50) return '#F59E0B';
    return '#DC2626';
}
function getRiskLevel(overdue_days, npa_risk) {
    if (npa_risk || overdue_days >= 30) return 'critical';
    if (overdue_days >= 14) return 'medium';
    return 'low';
}
function getInitials(name) {
    return (name || '??').split(' ').map((n)=>n[0]).join('').slice(0, 2);
}
